import{_ as t,o,c as a,aa as r}from"./chunks/framework.vXJbu8_U.js";const p=JSON.parse('{"title":"Migration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/migration.md","filePath":"guide/migration.md","lastUpdated":1781019088000}'),d={name:"guide/migration.md"};function c(i,e,n,s,l,h){return o(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="migration" tabindex="-1">Migration <a class="header-anchor" href="#migration" aria-label="Permalink to &quot;Migration&quot;">​</a></h1><h2 id="codemod-automated" tabindex="-1">Codemod (automated) <a class="header-anchor" href="#codemod-automated" aria-label="Permalink to &quot;Codemod (automated)&quot;">​</a></h2><p>A codemod handles the mechanical parts — rewriting imports and folding the standalone operators into the inline <code>createQuery</code> config:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> effector-refetch-codemod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;src/**/*.{ts,tsx}&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> effector-refetch-codemod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;src/**/*.ts&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # preview only</span></span></code></pre></div><p>It rewrites <code>@farfetched/core</code> → <code>effector-refetch</code>, turns <code>retry(q, …)</code> / <code>cache(q, …)</code> / <code>concurrency(q, { strategy })</code> into <code>createQuery({ retry, cache, concurrency })</code>, and drops the now-unused operator imports. Operators on a query it can&#39;t resolve statically are left as-is — review the diff and run your formatter after. The manual mapping below covers the rest.</p><h2 id="from-farfetched" tabindex="-1">From farfetched <a class="header-anchor" href="#from-farfetched" aria-label="Permalink to &quot;From farfetched&quot;">​</a></h2><p>The mental model is close, so most code maps directly. The main shift: <strong>bring your own effect</strong>, and inline options are available alongside operators.</p><table tabindex="0"><thead><tr><th>farfetched</th><th>effector-refetch</th></tr></thead><tbody><tr><td><code>createQuery({ handler })</code></td><td><code>createQuery({ effect })</code> (or <code>{ handler }</code>)</td></tr><tr><td><code>createJsonQuery({ ... })</code></td><td><code>createJsonQuery({ request, response })</code></td></tr><tr><td><code>retry(query, { times, delay })</code></td><td><code>retry(query, …)</code> <strong>or</strong> inline <code>createQuery({ retry })</code></td></tr><tr><td><code>cache(query, { ... })</code></td><td><code>cache(query, …)</code> <strong>or</strong> inline <code>createQuery({ cache })</code></td></tr><tr><td><code>concurrency(query, { strategy })</code></td><td><code>concurrency(query, …)</code> <strong>or</strong> inline <code>createQuery({ concurrency })</code></td></tr><tr><td><code>connectQuery({ source, fn, target })</code></td><td>identical</td></tr><tr><td><code>createMutation</code></td><td><code>createMutation</code> (+ <code>mutate</code> alias)</td></tr><tr><td>contracts</td><td><code>zodContract</code> / <code>standardSchemaContract</code> / <code>createContract</code></td></tr><tr><td><code>$data / $error / $status / $pending</code></td><td>same names</td></tr></tbody></table><p>Notable differences:</p><ul><li>The query wraps a <strong>real effect</strong> (<code>query.__.effect</code>), visible in devtools.</li><li>Cancellation is real for <code>createRequestFx</code> effects (AbortSignal), not just discard.</li><li>Sourced config is available inline (a <code>Store</code> for <code>concurrency</code> / <code>retry.times</code> / <code>cache.staleAfter</code> / <code>enabled</code>).</li><li><code>useUnit(query)</code> works directly in React and Vue via <code>@@unitShape</code>.</li></ul><p>What&#39;s not here yet (vs farfetched): a Solid binding, the full sourced surface on every field, and some JSON-contract conveniences. See the <a href="https://github.com/Olovyannikov/effector-query/blob/main/ROADMAP.md" target="_blank" rel="noreferrer">roadmap</a>.</p><h2 id="within-0-x" tabindex="-1">Within 0.x <a class="header-anchor" href="#within-0-x" aria-label="Permalink to &quot;Within 0.x&quot;">​</a></h2><p>Pre-1.0 the API may still change between minor versions; breaking changes are called out in the changelog. Notable so far:</p><ul><li>Web-storage cache adapters take an <strong>options object</strong> now: <code>localStorageCache({ version, maxAge })</code> (previously a prefix string).</li></ul>`,14)])])}const f=t(d,[["render",c]]);export{p as __pageData,f as default};
